def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        weight = 1.0
        decay = 0.95
        boost = 1.0
        modifiers = []
        for j in range(1, 15):
            if j % 4 == 0:
                weight *= 1.03 + 0.007 * j
            elif j % 6 == 0:
                weight *= 0.92 - 0.006 * j
            if ratio < 0.08 * j:
                increment = (j**3) / (1 + np.exp(-ratio * j)) * weight
            else:
                increment = (np.log1p(j*10) + ratio**2.5) * weight / (j + 3)
            score += increment
            if (cap * j + j*j) % 9 == 0:
                score *= 1.06
            elif (cap - j*j*j) % 11 == 0:
                score *= 0.94
            if j == 7:
                temp_penalty = 0.0
                for k in range(1, 7):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            temp_penalty += np.cbrt(diff) / (k + 4)
                        else:
                            temp_penalty -= np.log1p(abs(diff)) * 0.7 / (k + 3)
                    else:
                        temp_penalty -= abs(diff) ** 1.4 / (k + 6)
                score += temp_penalty * 0.75
            if ratio > 0.8:
                if j % 2 == 1:
                    boost *= 1.08 + 0.015 * j
                else:
                    boost *= 1.04 + 0.01 * j
            elif ratio < 0.15:
                if j % 5 == 0:
                    boost *= 0.85 - 0.02 * j
                elif j % 4 == 2:
                    boost *= 0.9 - 0.015 * j
            if (j + cap) % 3 == 0:
                modifiers.append(np.tanh(ratio * j))
            else:
                modifiers.append(np.cos(ratio + j/10))
        modifier_factor = np.mean(modifiers) if modifiers else 1.0
        score *= boost * modifier_factor
        if score < 0:
            adj_factor = np.log1p(cap + item) * np.sqrt(cap + 2)
            priorities[i] = -score * adj_factor
            if ratio > 0.9:
                priorities[i] *= 1.12
            if cap % 3 == 0:
                priorities[i] *= 0.97
            elif cap % 5 == 0:
                priorities[i] *= 1.03
        else:
            if cap > item * 5:
                base = np.sqrt(cap) + 1.5
                penalties = 1 + (np.sin(ratio * np.pi) * 0.2)
                priorities[i] = -score / base * penalties
            else:
                exp_penalty = np.exp(-ratio**2.2)
                div = (cap + 4)
                priorities[i] = -score / div * exp_penalty
            if ratio < 0.1:
                priorities[i] *= 0.7
            elif ratio > 0.85:
                priorities[i] *= 1.18
            if cap % 2 == 0:
                priorities[i] *= 0.96
            else:
                priorities[i] *= 1.04
        secondary_adj = 1.0
        for m in range(1, 5):
            if (cap + m*item) % (m+3) == 0:
                secondary_adj *= 1 + 0.05 * m * ratio
            else:
                secondary_adj *= 0.98 - 0.01 * m
        priorities[i] *= secondary_adj
    return priorities
